import{_ as e,o as i,c as a,a2 as n}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Plugin Settings","description":"AkuraiGeo Plugin Settings","frontmatter":{"title":"Plugin Settings","description":"AkuraiGeo Plugin Settings","weight":20,"extra":{"order":20},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai-geo/settings"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai-geo/settings"}],["meta",{"property":"og:title","content":"Plugin Settings"}],["meta",{"property":"og:description","content":"AkuraiGeo Plugin Settings"}],["meta",{"name":"twitter:title","content":"Plugin Settings"}],["meta",{"name":"twitter:description","content":"AkuraiGeo Plugin Settings"}]]},"headers":[],"relativePath":"docs/akurai-geo/settings.md","filePath":"docs/akurai-geo/settings.md"}'),o={name:"docs/akurai-geo/settings.md"};function s(r,t,g,u,l,c){return i(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="plugin-settings" tabindex="-1">Plugin Settings <a class="header-anchor" href="#plugin-settings" aria-label="Permalink to &quot;Plugin Settings&quot;">​</a></h1><p>To adjust the plugin settings visit <strong>AkuraiGeo</strong> page in your WordPress Dashboard where you can define all plugin options.</p><hr><h2 id="adjusting-settings" tabindex="-1">Adjusting Settings <a class="header-anchor" href="#adjusting-settings" aria-label="Permalink to &quot;Adjusting Settings&quot;">​</a></h2><p>On this page you can register the plugin, as well as adjust all its settings.</p><h3 id="plugin-activation" tabindex="-1">Plugin Activation <a class="header-anchor" href="#plugin-activation" aria-label="Permalink to &quot;Plugin Activation&quot;">​</a></h3><p>Copy your license key from your <a href="https://dinomatic.com/account" target="_blank" rel="noreferrer">DinoMatic account</a>, paste it here and click the &quot;Update&quot; button. Upon unsuccessful registration, you&#39;ll receive a message and will be asked to try again.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-settings--registration.png" alt="AkuraiGeo Plugin Activation"></p><p>If you get an error that the license key is not correct and the registration fails:</p><ul><li>make sure there are no white spaces in the beginning or at the end of the key</li><li>if you have firewall installed on your server, make sure requests to dinomatic.com are not being blocked</li></ul><h3 id="target-countries" tabindex="-1">Target Countries <a class="header-anchor" href="#target-countries" aria-label="Permalink to &quot;Target Countries&quot;">​</a></h3><p>In order to make it easier, Akurai Geo plugin offers you to select your target countries in advance and all your blocks and other geo options will be then based on those countries.</p><p><img src="https://media.dinomatic.com/images/docs/akurai-geo/akurai-geo-settings--countries.png" alt="AkuraiGeo Settings - Countries"></p>',13)])])}const h=e(o,[["render",s]]);export{p as __pageData,h as default};
